294			// Check document selectors for being overly generic. Technically this isn't a problem but
295			// in practice many extensions say they support `fooLang` but need fs-access to do so. Those
296			// extension should specify then the `file`-scheme, e.g. `{ scheme: 'fooLang', language: 'fooLang' }`
297			// We only inform once, it is not a warning because we just want to raise awareness and because
298			// we cannot say if the extension is doing it right or wrong...
299			const checkSelector = (function () {
300				let done = !extension.isUnderDevelopment;
301				function informOnce() {
302					if (!done) {
303						extHostLogService.info(`Extension '${extension.identifier.value}' uses a document selector without scheme. Learn more about this: https://go.microsoft.com/fwlink/?linkid=872305`);
304						done = true;
305					}
306				}
307				return function perform(selector: vscode.DocumentSelector): vscode.DocumentSelector {
308					if (Array.isArray(selector)) {
309						selector.forEach(perform);
310					} else if (typeof selector === 'string') {
311						informOnce();
312					} else {
313						const filter = selector as vscode.DocumentFilter; // TODO: microsoft/TypeScript#42768
314						if (typeof filter.scheme === 'undefined') {
315							informOnce();
316						}
317						if (typeof filter.exclusive === 'boolean') {
318							checkProposedApiEnabled(extension, 'documentFiltersExclusive');
319						}
320					}
321					return selector;
322				};
323			})();
